require(['jquery', 'xwiki-selectize'], function ($) {
  console.debug('yellow');
  setTimeout(function () {
    $('.proj-manag-relation').each(function () {
      let root = $(this);
      let client = root.data('client');
      if (!client) {
        return;
      }

      root.find('.proj-manag-relation-property dd').each(function () {
        let valueContainer = $(this);

        // Callback function to execute when mutations are observed
        const callback = (mutationList, observer) => {
          observer.disconnect();
          let clientParams = root.data('params') && root.data('params');
          let workItemREST = XWiki.contextPath + "/rest/wikis/" + XWiki.currentWiki + "/projectmanagement/" + client + "/workitems";
          let projectsREST = XWiki.contextPath + "/rest/wikis/" + XWiki.currentWiki + "/projectmanagement/" + client + "/projects";
          if (valueContainer.find(':input').length > 0) {
            return;
          }
          valueContainer.addClass('loading');
          // If view mode load information for the ids.
          let entityId = valueContainer.text().trim();
          if (!entityId) {
            valueContainer.removeClass('loading');
            observer.observe(valueContainer[0], { childList: true });
            return;
          }
          let url = workItemREST;
          let dataType = valueContainer.data('prop') || 'workItem';
          if (dataType == 'project') {
            url = projectsREST;
          }
          $.getJSON(url + "/" + entityId, clientParams)
            .done(function (response) {
              let anchor = '';
              let href = '';
              if (dataType == 'project') {
                anchor = response.name;
                href = response.identifier.location;
              } else {
                anchor = response.summary.value;
                href = response.summary.location;
              }
              valueContainer.html($('<a/>').attr('href', href).text(anchor));
            })
            .fail(function (_jqxhr, textStatus, error) {
              new XWiki.widgets.Notification('Failed to load the entity information.', 'error');
            })
            .always(function () {
              valueContainer.removeClass('loading');
              observer.observe(valueContainer[0], { childList: true });
            });

        };

        // Create an observer instance linked to the callback function
        const observer = new MutationObserver(callback);

        callback([], observer);

        // Start observing the target node for configured mutations
        // observer.observe(valueContainer[0], { childList: true });
      });
      let initInput = function (propRoot, root) {
          let input = propRoot.find(':input');
          if (input <= 0 || input[0].selectize) {
            return;
          }
          let clientParams = root.data('params') && root.data('params');
          let workItemREST = XWiki.contextPath + "/rest/wikis/" + XWiki.currentWiki + "/projectmanagement/" + client + "/workitems";
          let projectsREST = XWiki.contextPath + "/rest/wikis/" + XWiki.currentWiki + "/projectmanagement/" + client + "/projects";
          let url = workItemREST;
          let dataType = propRoot.find('dd').data('prop') || 'workPackage';
          if (dataType == 'project') {
            url = projectsREST;
          }
          let selectizeCfg = {
            create: true,
            maxItems: 1
          };
          let cfg = {
            query: {
              filters: [
                {
                  property: "summary",
                  constraints: [
                    {
                      "operator": "contains"
                    }
                  ]
                }
              ]
            }
          };
          let firstLoad = true;
          selectizeCfg.load = function (text, callback) {
            let urlParams = { ...clientParams };
            if (cfg.query.filters.length <= 0) {
              if (input[0].selectize && Object.keys(input[0].selectize.options).length > 1) {
                callback([]);
                return;
              }
            } else {
              cfg.query.filters[0].constraints[0].value = text;
            }
            cfg.query.filters[0].constraints[0].operator = 'contains';
            cfg.query.filters[0].property = 'summary';
            if (dataType == 'project') {
              cfg.query.filters[0].property = 'name';
            }
            if (firstLoad) {
              cfg.query.filters[0].property = 'id';
              cfg.query.filters[0].constraints[0].operator = 'equals';
              firstLoad = false;
            }
            urlParams.filter = JSON.stringify(cfg);
            $.getJSON(url, urlParams)
              .then(function (results) {
                let items = (results && results.items) || [];
                if (dataType == 'project') {
                  items = items.map(item => { return { label: item.name, value: item.identifier.value, hint: item.identifier.value }});
                } else {
                  items = items.map(item => { return { label: item.summary.value, value: item.identifier.value, hint: item.project.value }});
                }
                callback(items);
              })
              .catch(function (e) {
                console.log(`error trying to retrieve selectize searchUrl ${searchURL} elements.` + e);
                callback([]);
              });
          };
          input.xwikiSelectize(selectizeCfg);
      };
      root.find('.proj-manag-relation-property').each(function () {
        let propRoot = $(this);
        if (XWiki.contextaction == 'edit') {
          initInput(propRoot, root);
        }
        propRoot.on('focus', ':input', function () {
          initInput(propRoot, root);
        });
      });
    });
  });
});
